113→/**
114→ * Creates a workspace and identity directly in SurrealDB for learning tests.
115→ * Returns workspace ID and identity ID for use in test scenarios.
116→ */
117→export async function createTestWorkspace(
118→  surreal: Surreal,
119→  suffix: string,
120→): Promise<{ workspaceId: string; identityId: string }> {
121→  const workspaceId = `ws-${crypto.randomUUID()}`;
122→  const identityId = `id-${crypto.randomUUID()}`;
123→  const workspaceRecord = new RecordId("workspace", workspaceId);
124→  const identityRecord = new RecordId("identity", identityId);
125→
126→  await surreal.query(`CREATE $workspace CONTENT $content;`, {
127→    workspace: workspaceRecord,
128→    content: {
129→      name: `Learning Test Workspace ${suffix}`,
130→      status: "active",
131→      onboarding_complete: true,
132→      onboarding_turn_count: 0,
133→      onboarding_summary_pending: false,
134→      onboarding_started_at: new Date(),
135→      created_at: new Date(),
136→    },
137→  });
138→
139→  await surreal.query(`CREATE $identity CONTENT $content;`, {
140→    identity: identityRecord,
141→    content: {
142→      name: `Test User ${suffix}`,
143→      type: "human",
144→      identity_status: "active",
145→      workspace: workspaceRecord,
146→      created_at: new Date(),
147→    },
148→  });
149→
150→  await surreal.query(
151→    `RELATE $identity->member_of->$workspace SET added_at = time::now();`,
152→    { identity: identityRecord, workspace: workspaceRecord },
153→  );
154→
155→  return { workspaceId, identityId };
156→}
