  2→import { LEARNING_TYPES, type LearningStatus, type LearningType } from "../../shared/contracts";
  3→import { HttpError } from "../http/errors";
  4→import { logError, logInfo, logWarn } from "../http/observability";
  5→import { jsonError, jsonResponse } from "../http/response";
  6→import type { ServerDependencies } from "../runtime/types";
  7→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
  8→import { createEmbeddingVector } from "../graph/embeddings";
  9→import {
 10→  createLearning,
 11→  listWorkspaceLearnings,
 12→  updateLearningStatus,
 13→  updateLearningText,
 14→} from "./queries";
 15→import { checkCollisions, type CollisionResult } from "./collision";
 16→import type { LearningRecord } from "./types";
 17→
 18→// ---------------------------------------------------------------------------
 19→// Valid state transitions
 20→// ---------------------------------------------------------------------------
 21→
 22→const VALID_TRANSITIONS: Record<string, Record<string, LearningStatus>> = {
 23→  pending_approval: {
 24→    approve: "active",
 25→    dismiss: "dismissed",
 26→  },
 27→  active: {
 28→    deactivate: "deactivated",
 29→  },
 30→};
 31→
 32→const VALID_ACTIONS = ["approve", "dismiss", "deactivate", "supersede"] as const;
 33→type LearningAction = (typeof VALID_ACTIONS)[number];
