572→        DPoP: proof,
573→      },
574→      body: options?.body !== undefined ? JSON.stringify(options.body) : JSON.stringify({}),
575→    });
576→  };
577→
578→  return {
579→    ...user,
580→    mcpHeaders: { Authorization: `DPoP ${access_token}` },
581→    mcpFetch,
