 1→#!/usr/bin/env bun
 2→import { readdirSync, statSync } from "node:fs";
 3→import { join } from "node:path";
 4→
 5→const root = "tests/acceptance";
 6→const dirs = readdirSync(root)
 7→  .filter((name) => statSync(join(root, name)).isDirectory())
 8→  .sort();
 9→
10→console.log(`Running ${dirs.length} acceptance shards in parallel:\n`);
11→console.log(dirs.map((d) => `  • ${d}`).join("\n"));
12→console.log();
13→
14→const started = performance.now();
15→
16→const results = await Promise.allSettled(
17→  dirs.map(async (dir) => {
18→    const start = performance.now();
19→    const proc = Bun.spawn(
20→      [
21→        "bun",
22→        "test",
23→        "--concurrent",
24→        "--timeout=180000",
25→        join(root, dir) + "/",
26→      ],
27→      {
28→        env: { ...process.env, FORCE_COLOR: "1" },
29→        stdout: "pipe",
30→        stderr: "pipe",
31→      },
32→    );
33→
34→    const [stdout, stderr] = await Promise.all([
35→      new Response(proc.stdout).text(),
36→      new Response(proc.stderr).text(),
37→    ]);
38→    const exitCode = await proc.exited;
39→    const elapsed = ((performance.now() - start) / 1000).toFixed(1);
40→
41→    return { dir, exitCode, stdout, stderr, elapsed };
42→  }),
43→);
44→
45→console.log("─".repeat(70));
46→console.log();
47→
48→let failed = 0;
49→
50→for (const result of results) {
51→  if (result.status === "rejected") {
52→    failed++;
53→    console.log(`✗ (spawn error) ${result.reason}`);
54→    continue;
55→  }
56→
57→  const { dir, exitCode, stdout, stderr, elapsed } = result.value;
58→  const icon = exitCode === 0 ? "✓" : "✗";
59→  const summary = stdout
60→    .split("\n")
61→    .find((l) => l.includes("pass") || l.includes("fail"));
62→
63→  console.log(`${icon} ${dir.padEnd(30)} ${(elapsed + "s").padStart(8)}  ${summary?.trim() ?? ""}`);
64→
65→  if (exitCode !== 0) {
66→    failed++;
67→    const output = (stdout + stderr).trim();
68→    if (output) {
69→      console.log(
70→        output
71→          .split("\n")
72→          .map((l) => `    ${l}`)
73→          .join("\n"),
74→      );
75→    }
76→    console.log();
77→  }
78→}
79→
80→const total = ((performance.now() - started) / 1000).toFixed(1);
81→console.log();
82→console.log(`─`.repeat(70));
83→console.log(
84→  `${failed === 0 ? "✓" : "✗"} ${results.length} shards finished in ${total}s — ${failed} failed`,
85→);
86→
87→process.exit(failed > 0 ? 1 : 0);
88→

  1→/**
  2→ * Milestone 6: Collision Detection
  3→ *
  4→ * Traces: US-AL-006 (learning collision detection)
  5→ *
  6→ * IMPORTANT: These tests call a real LLM for intent classification and
  7→ * a real embedding model for vector similarity. Required env vars:
  8→ * OPENROUTER_API_KEY, OPENROUTER_EMBEDDING_MODEL, EXTRACTION_MODEL.
  9→ *
 10→ * Validates:
 11→ * - Learning-vs-learning collision: near-duplicate (>0.90), contradiction (0.75-0.90 + LLM), no collision (<0.75)
 12→ * - Policy collision is a hard block (learning cannot override governance)
 13→ * - Decision collision is informational (reinforces or warns, never blocks)
 14→ * - LLM intent classification distinguishes contradicts/reinforces/unrelated
 15→ * - Fail-open for human-created learnings when embedding unavailable
 16→ * - Workspace boundary isolation for collision detection
 17→ *
 18→ * Driving ports:
 19→ *   POST /api/workspaces/:workspaceId/learnings  (create with collision check)
 20→ *   SurrealDB direct queries                     (seed existing learnings/policies/decisions)
 21→ */
 22→import { describe, expect, it } from "bun:test";
 23→import {
 24→  setupLearningSuite,
 25→  createTestWorkspace,
 26→  createTestLearning,
 27→  createTestLearningWithEmbedding,
 28→  createTestPolicyWithEmbedding,
 29→  createTestDecisionWithEmbedding,
 30→  createLearningViaHttp,
 31→  getLearningById,
 32→  generateEmbedding,
 33→  createTestUser,
 34→} from "./learning-test-kit";
 35→
 36→const getRuntime = setupLearningSuite("learning_m6_collision");
 37→
 38→describe("Milestone 6: Collision Detection", () => {
 39→  // -------------------------------------------------------------------------
 40→  // US-AL-006: Learning-vs-learning near-duplicate detection (>0.90)
 41→  // -------------------------------------------------------------------------
 42→
 43→  it("near-duplicate learning detected when texts are semantically identical", async () => {
 44→    const { baseUrl, surreal } = getRuntime();
 45→
 46→    // Given a workspace with an active learning about null usage
 47→    const { workspaceId } = await createTestWorkspace(surreal, "near-dup");
 48→    await createTestLearningWithEmbedding(surreal, workspaceId, {
 49→      text: "Never use null for domain data values. Represent absence with omitted optional fields.",
 50→      learning_type: "constraint",
 51→      status: "active",
 52→    });
 53→
 54→    // When creating a learning with nearly identical meaning
 55→    const user = await createTestUser(baseUrl, `dup-${crypto.randomUUID()}`);
 56→    const response = await createLearningViaHttp(baseUrl, user, workspaceId, {
 57→      text: "Do not use null in domain data. Use omitted optional fields to represent absence.",
 58→      learning_type: "constraint",
 59→      priority: "medium",
 60→    });
 61→
 62→    // Then the response indicates a near-duplicate collision (similarity >0.90)
 63→    const body = await response.json();
 64→    expect(body.collisions).toBeDefined();
 65→    const duplicates = body.collisions.filter(
 66→      (c: { collisionType: string }) => c.collisionType === "duplicates",
 67→    );
 68→    expect(duplicates.length).toBeGreaterThanOrEqual(1);
 69→    expect(duplicates[0].similarity).toBeGreaterThan(0.90);
 70→  }, 120_000);
 71→
 72→  // -------------------------------------------------------------------------
 73→  // US-AL-006: Learning-vs-learning contradiction via LLM (0.75-0.90)
 74→  // -------------------------------------------------------------------------
 75→
 76→  it("LLM classifies contradicting learnings in the ambiguous similarity zone", async () => {
 77→    const { baseUrl, surreal } = getRuntime();
 78→
 79→    // Given an active learning recommending one approach
 80→    const { workspaceId } = await createTestWorkspace(surreal, "llm-contra");
 81→    await createTestLearningWithEmbedding(surreal, workspaceId, {
 82→      text: "Always use PostgreSQL for all new database services. No other databases allowed.",
 83→      learning_type: "constraint",
 84→      status: "active",
 85→      target_agents: ["code_agent"],
 86→    });
